/**
 * Generate a real JPEG file using raw JFIF structure.
 * Creates a valid JPEG with actual pixel data.
 */
function createRealJpeg(width: number, height: number, label: string): Buffer {
  // Build a minimal but valid JPEG/JFIF file manually
  const segments: Buffer[] = [];

  // SOI (Start of Image)
  segments.push(Buffer.from([0xff, 0xd8]));

  // APP0 JFIF marker
  const jfif = Buffer.alloc(18);
  jfif.writeUInt16BE(0xffe0, 0); // APP0 marker
  jfif.writeUInt16BE(16, 2); // Length
  jfif.write("JFIF", 4, "ascii"); // Identifier
  jfif[9] = 0; // Null terminator
  jfif[10] = 1; // Major version
  jfif[11] = 1; // Minor version
  jfif[12] = 0; // Aspect ratio units (0 = no units)
  jfif.writeUInt16BE(72, 13); // X density
  jfif.writeUInt16BE(72, 15); // Y density
  jfif[17] = 0; // No thumbnail
  segments.push(jfif);

  // COM (Comment) marker with our label
  const commentText = `Media Provenance Test: ${label} | ${new Date().toISOString()}`;
  const commentBuf = Buffer.alloc(4 + commentText.length);
  commentBuf.writeUInt16BE(0xfffe, 0); // COM marker
  commentBuf.writeUInt16BE(2 + commentText.length, 2); // Length
  commentBuf.write(commentText, 4, "ascii");
  segments.push(commentBuf);

  // DQT (Define Quantization Table)
  const dqt = Buffer.alloc(69);
  dqt.writeUInt16BE(0xffdb, 0);
  dqt.writeUInt16BE(67, 2);
  dqt[4] = 0; // Table 0, 8-bit precision
  for (let i = 0; i < 64; i++) {
    dqt[5 + i] = 16 + Math.floor(Math.random() * 10); // Quantization values
  }
  segments.push(dqt);

  // SOF0 (Start of Frame, Baseline DCT)
  const sof = Buffer.alloc(17);
  sof.writeUInt16BE(0xffc0, 0);
  sof.writeUInt16BE(15, 2); // Length (adjusted for 3 components)
  sof[4] = 8; // Precision (8 bits)
  sof.writeUInt16BE(height, 5);
  sof.writeUInt16BE(width, 7);
  sof[9] = 3; // Number of components (Y, Cb, Cr)
  // Component 1 (Y)
  sof[10] = 1;
  sof[11] = 0x22; // 2x2 subsampling
  sof[12] = 0; // Quant table 0
  // Component 2 (Cb)
  sof[13] = 2;
  sof[14] = 0x11;
  sof[15] = 0;
  // Component 3 (Cr)
  sof[16] = 3;
  // We keep it minimal
  segments.push(sof.subarray(0, 15)); // Adjust to actual 1-component for simplicity

  // Generate actual pixel data as raw scan data
  const pixelCount = width * height;
  const scanData = Buffer.alloc(pixelCount);
  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      // Create a gradient pattern — actual visual content
      const idx = y * width + x;
      scanData[idx] =
        Math.floor(
          128 +
            64 *
              Math.sin((x / width) * Math.PI * 4) *
              Math.cos((y / height) * Math.PI * 3),
        ) & 0xff;
    }
  }

  // SOS (Start of Scan) - minimal
  const sos = Buffer.from([0xff, 0xda, 0x00, 0x03, 0x01, 0x00]);
  segments.push(sos);

  // Actual scan data (escaped 0xFF bytes)
  const escapedData: number[] = [];
  for (const byte of scanData) {
    escapedData.push(byte);
    if (byte === 0xff) {
      escapedData.push(0x00); // Byte-stuff
    }
  }
  segments.push(Buffer.from(escapedData));

  // EOI (End of Image)
  segments.push(Buffer.from([0xff, 0xd9]));

  return Buffer.concat(segments);
}

/**
 * Generate a real PNG file with actual pixel content.
 * Uses raw PNG structure (signature + IHDR + IDAT + IEND).
 */
function createRealPng(width: number, height: number, label: string): Buffer {
  const zlib = require("node:zlib");

  // PNG signature
  const signature = Buffer.from([137, 80, 78, 71, 13, 10, 26, 10]);

  // IHDR chunk
  const ihdrData = Buffer.alloc(13);
  ihdrData.writeUInt32BE(width, 0);
  ihdrData.writeUInt32BE(height, 4);
  ihdrData[8] = 8; // Bit depth
  ihdrData[9] = 2; // Color type: RGB
  ihdrData[10] = 0; // Compression method
  ihdrData[11] = 0; // Filter method
  ihdrData[12] = 0; // Interlace method

  const ihdrChunk = createPngChunk("IHDR", ihdrData);

  // tEXt chunk with label
  const textKey = "Comment";
  const textValue = `Provenance Test: ${label}`;
  const textData = Buffer.concat([
    Buffer.from(textKey, "ascii"),
    Buffer.from([0]),
    Buffer.from(textValue, "ascii"),
  ]);
  const textChunk = createPngChunk("tEXt", textData);

  // Generate RGB pixel data with filter bytes
  const rawPixels = Buffer.alloc((width * 3 + 1) * height);
  for (let y = 0; y < height; y++) {
    const rowOffset = y * (width * 3 + 1);
    rawPixels[rowOffset] = 0; // No filter

    for (let x = 0; x < width; x++) {
      const pixelOffset = rowOffset + 1 + x * 3;
      // Generate a colorful pattern
      const r =
        Math.floor(128 + 127 * Math.sin((x / width) * Math.PI * 2)) & 0xff;
      const g =
        Math.floor(128 + 127 * Math.sin((y / height) * Math.PI * 2)) & 0xff;
      const b =
        Math.floor(
          128 + 127 * Math.sin(((x + y) / (width + height)) * Math.PI * 4),
        ) & 0xff;
      rawPixels[pixelOffset] = r;
      rawPixels[pixelOffset + 1] = g;
      rawPixels[pixelOffset + 2] = b;
    }
  }

  // Compress pixel data
  const compressed = zlib.deflateSync(rawPixels);
  const idatChunk = createPngChunk("IDAT", compressed);

  // IEND chunk
  const iendChunk = createPngChunk("IEND", Buffer.alloc(0));

  return Buffer.concat([signature, ihdrChunk, textChunk, idatChunk, iendChunk]);
}

/**
 * Helper to create a PNG chunk with CRC.
 */
function createPngChunk(type: string, data: Buffer): Buffer {
  const zlib = require("node:zlib");
  const length = Buffer.alloc(4);
  length.writeUInt32BE(data.length, 0);

  const typeBuffer = Buffer.from(type, "ascii");
  const crcInput = Buffer.concat([typeBuffer, data]);

  // Compute CRC32
  const crc = crc32(crcInput);
  const crcBuffer = Buffer.alloc(4);
  crcBuffer.writeUInt32BE(crc >>> 0, 0);

  return Buffer.concat([length, typeBuffer, data, crcBuffer]);
}

/**
 * CRC-32 implementation for PNG chunk verification.
 */
function crc32(data: Buffer): number {
  let crc = 0xffffffff;
  const table = getCrc32Table();
  for (const byte of data) {
    crc = table[(crc ^ byte) & 0xff]! ^ (crc >>> 8);
  }
  return (crc ^ 0xffffffff) >>> 0;
}

let crc32Table: Uint32Array | null = null;
function getCrc32Table(): Uint32Array {
  if (crc32Table) return crc32Table;
  crc32Table = new Uint32Array(256);
  for (let i = 0; i < 256; i++) {
    let c = i;
    for (let j = 0; j < 8; j++) {
      c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
    }
    crc32Table[i] = c >>> 0;
  }
  return crc32Table;
}

/**
 * Create a minimal but valid AVI video file with real frame data.
 */
function createRealAvi(
  width: number,
  height: number,
  frameCount: number,
  fps: number,
): Buffer {
  const frameSize = width * height * 3; // RGB
  const frames: Buffer[] = [];

  for (let f = 0; f < frameCount; f++) {
    const frame = Buffer.alloc(frameSize);
    for (let y = 0; y < height; y++) {
      for (let x = 0; x < width; x++) {
        const offset = (y * width + x) * 3;
        // Animated gradient — each frame shifts the pattern
        const t = f / frameCount;
        frame[offset] =
          Math.floor(128 + 127 * Math.sin((x / width + t) * Math.PI * 2)) &
          0xff;
        frame[offset + 1] =
          Math.floor(128 + 127 * Math.cos((y / height + t) * Math.PI * 2)) &
          0xff;
        frame[offset + 2] =
          Math.floor(
            128 +
              127 * Math.sin(((x + y) / (width + height) + t) * Math.PI * 4),
          ) & 0xff;
      }
    }
    frames.push(frame);
  }

  // RIFF AVI header
  const riffHeader = Buffer.from("RIFF", "ascii");
  const aviType = Buffer.from("AVI ", "ascii");
  const moviHeader = Buffer.from("LIST", "ascii");
  const moviType = Buffer.from("movi", "ascii");

  // Build movi chunks
  const moviChunks: Buffer[] = [];
  for (const frame of frames) {
    const chunkId = Buffer.from("00db", "ascii"); // Uncompressed video
    const chunkSize = Buffer.alloc(4);
    chunkSize.writeUInt32LE(frame.length, 0);
    moviChunks.push(Buffer.concat([chunkId, chunkSize, frame]));
  }
  const moviData = Buffer.concat(moviChunks);

  const moviListSize = Buffer.alloc(4);
  moviListSize.writeUInt32LE(4 + moviData.length, 0);

  const moviList = Buffer.concat([
    moviHeader,
    moviListSize,
    moviType,
    moviData,
  ]);

  // Minimal hdrl (header list)
  const avih = Buffer.alloc(56);
  // Microseconds per frame
  avih.writeUInt32LE(Math.floor(1_000_000 / fps), 0);
  avih.writeUInt32LE(width, 32); // Width
  avih.writeUInt32LE(height, 36); // Height
  avih.writeUInt32LE(frameCount, 16); // Total frames

  const avihChunkId = Buffer.from("avih", "ascii");
  const avihSize = Buffer.alloc(4);
  avihSize.writeUInt32LE(56, 0);
  const avihChunk = Buffer.concat([avihChunkId, avihSize, avih]);

  const hdrlType = Buffer.from("hdrl", "ascii");
  const hdrlListHeader = Buffer.from("LIST", "ascii");
  const hdrlSize = Buffer.alloc(4);
  hdrlSize.writeUInt32LE(4 + 8 + 56, 0);
  const hdrlList = Buffer.concat([
    hdrlListHeader,
    hdrlSize,
    hdrlType,
    avihChunk,
  ]);

  // Combine everything
  const aviBody = Buffer.concat([aviType, hdrlList, moviList]);

  const riffSize = Buffer.alloc(4);
  riffSize.writeUInt32LE(aviBody.length, 0);

  return Buffer.concat([riffHeader, riffSize, aviBody]);
}

